import anthropic, json

client = anthropic.Anthropic()

CONFIDENCE_TOOL = {
    "name": "rate_confidence",
    "description": "Rate your confidence in your answer",
    "input_schema": {
        "type": "object",
        "properties": {
            "level": {
                "type": "string",
                "enum": ["high", "medium", "low"],
                "description": (
                    "high: multiple consistent authoritative sources or well-established facts. "
                    "medium: one primary source, or inference from related facts. "
                    "low: conflicting sources, speculation, or outside your knowledge."
                ),
            },
            "reason": {
                "type": "string",
                "description": "One sentence explaining the confidence rating.",
            },
            "caveats": {
                "type": "array",
                "items": {"type": "string"},
                "description": "Specific limitations or edge cases the user should know.",
            },
        },
        "required": ["level", "reason"],
    },
}

ANSWER_TOOL = {
    "name": "provide_answer",
    "description": "Provide the final answer to the user",
    "input_schema": {
        "type": "object",
        "properties": {
            "text": {"type": "string", "description": "The answer text"},
        },
        "required": ["text"],
    },
}

def answer_with_confidence(
    question: str,
    context: str | None = None,
) -> dict:
    """
    Returns answer text plus a structured confidence rating.
    Uses tool_choice=any so the model can call both tools in one turn.
    """
    messages = [{"role": "user", "content": question}]
    if context:
        messages[0]["content"] = f"Context:\n{context}\n\nQuestion: {question}"

    response = client.messages.create(
        model="claude-sonnet-5",
        max_tokens=1024,
        tools=[ANSWER_TOOL, CONFIDENCE_TOOL],
        messages=messages,
    )

    result = {"answer": "", "confidence": {"level": "medium", "reason": "", "caveats": []}}
    for block in response.content:
        if block.type == "tool_use":
            if block.name == "provide_answer":
                result["answer"] = block.input["text"]
            elif block.name == "rate_confidence":
                result["confidence"] = block.input
        elif block.type == "text":
            result["answer"] = result["answer"] or block.text

    return result

function renderConfidenceBadge({ level, reason, caveats = [] }) {
  const config = {
    high:   { label: "High confidence", bg: "#052e16", border: "#22c55e", text: "#4ade80" },
    medium: { label: "Medium confidence", bg: "#451a03", border: "#f59e0b", text: "#fbbf24" },
    low:    { label: "Low confidence", bg: "#450a0a", border: "#ef4444", text: "#f87171" },
  }[level] ?? { label: "Unknown", bg: "#1e293b", border: "#475569", text: "#94a3b8" };

  const caveatHtml = caveats.length
    ? `<ul class="caveats">${caveats.map(c => `<li>${escapeHtml(c)}</li>`).join("")}</ul>`
    : "";

  return `
    <div class="confidence-wrapper">
      <span class="confidence-badge"
            style="background:${config.bg};border:1px solid ${config.border};color:${config.text}"
            title="${escapeAttr(reason)}">
        ${config.label}
      </span>
      ${reason ? `<span class="confidence-reason">${escapeHtml(reason)}</span>` : ""}
      ${caveatHtml}
      ${level === "low" ? '<p class="verify-note">⚠ Please verify this independently before acting on it.</p>' : ""}
    </div>
  `;
}

import pytest

def test_high_confidence_proceeds():
    result = answer_with_confidence("What is 2+2?")
    assert result["confidence"]["level"] == "high"

def test_low_stakes_medium_confidence_proceeds():
    action = decide_escalation("medium", "low", answer_involves_action=False)
    assert action == EscalationAction.PROCEED

def test_high_stakes_low_confidence_blocks():
    action = decide_escalation("low", "high", answer_involves_action=True)
    assert action == EscalationAction.BLOCK_ACTION

def test_hedge_words_lower_confidence():
    answer = "I think this might be correct, but I'm not entirely sure."
    result = compute_heuristic_confidence(answer, num_sources_cited=0, num_sources_available=3)
    assert result["level"] in {"medium", "low"}
    assert result["hedge_count"] >= 2

def test_many_sources_raise_confidence():
    answer = "The answer is definitively X."  # no hedges
    low_src = compute_heuristic_confidence(answer, 0, 5)
    high_src = compute_heuristic_confidence(answer, 5, 5)
    assert high_src["score"] > low_src["score"]
